#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

ret = GetPixel(vUvOriginal) - 0.004;


vec2 d = uTexSize.zw*2;
vec3 dx = ( GetBlur1(vUv+vec2(1,0)*d)-GetBlur1(vUv-vec2(1,0)*d) );
vec3 dy = ( GetBlur1(vUv+vec2(0,1)*d)-GetBlur1(vUv-vec2(0,1)*d) );

vec2 dither_uv = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw + rand_frame.xy;

vec2 uv_red = mix(vUvOriginal,vUv,-.4) - vec2(dx.x,dy.x)*uTexSize.zw + (texture(sampler_noise_lq, dither_uv).xyz-0.5)*uTexSize.zw*2;
ret.x = GetPixel(uv_red).x - 0.001;

vec2 uv_green = mix(vUvOriginal,vUv,1) + vec2(-1,2)*uTexSize.zw - vec2(dx.y,dy.y)*uTexSize.zw*3 + vec2(dx.x,dy.x)*uTexSize.zw*0;
ret.y = max( GetPixel(vUvOriginal).z - GetPixel(vUvOriginal).x*2, tex2d(sampler_fc_main, uv_green).y - 0.004);

vec2 uv_blue = mix(vUvOriginal,vUv,-0.2) + vec2(dx.z,dy.z)*uTexSize.zw*2;

ret.z = tex2d(sampler_fc_main,uv_blue).z;
ret.z += -(GetPixel(uv_blue).z - GetBlur1(uv_blue).z)*0.04 - 0.08 + ret.x*0.2;
//ret = 0;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 d = uTexSize.zw*8;
vec3 dx = ( GetBlur1(vUv+vec2(1,0)*d)-GetBlur1(vUv-vec2(1,0)*d) );
vec3 dy = ( GetBlur1(vUv+vec2(0,1)*d)-GetBlur1(vUv-vec2(0,1)*d) );

vec2 uv_fire = vUv + vec2(dx.z,dy.z)*0.02 - vec2(dx.y,dy.y)*uTexSize.zw*16;
ret = GetBlur3(uv_fire).y*vec3(1.7,0,0);
ret = mix(ret, vec3(-0.4,-0.5,0), GetBlur1(uv_fire).y*1.2);
ret = mix(ret, vec3(2,2,0),GetPixel(uv_fire).y*0.9);


vUv += vec2(dx.z, dy.z)*uTexSize.zw*2;

ret = mix(ret, 0, GetBlur1(vUv).z*2);
ret = mix(clamp01(ret), vec3(0.7,0.6,1), GetPixel(vUv).z);

ret = mix(ret, vec3(1,0.9,0.9), clamp01(GetPixel(vUv).x*2-1)*1.2);

  fragColor = ret;
}
